from machine import Pin, ADC
import network
import time
from umqtt.simple import MQTTClient

# Configuration
broker_ip = "your_broker_ip"
client_id = "esp32_sensor"
topic = "sensors/temp"

# Connect to Wi-Fi
def connect_wifi(ssid, password):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(ssid, password)
    while not wlan.isconnected():
        time.sleep(1)

# Initialize MQTT client
client = MQTTClient(client_id, broker_ip)

# Read temperature from ADC (replace with actual temperature sensor code)
def read_temperature():
    adc = ADC(Pin(34))  # Change to the pin connected to your sensor
    voltage = adc.read() * (3.3 / 4095)  # Assuming 12-bit ADC and 3.3V reference
    temperature = (voltage - 0.5) * 100  # Example conversion, adjust for your sensor
    return temperature

# Main loop
def main():
    connect_wifi("your_ssid", "your_password")
    client.connect()
    
    while True:
        temp = read_temperature()
        client.publish(topic, str(temp))
        print("Published: {} to topic: {}".format(temp, topic))
        time.sleep(10)  # Adjust frequency of publishing

# Start the program
main()